import { html, customElement } from '@umbraco-cms/backoffice/external/lit';
import { UmbModalBaseElement } from '@umbraco-cms/backoffice/modal';
import { UMB_ACTION_EVENT_CONTEXT } from '@umbraco-cms/backoffice/action';
import { UmbRequestReloadChildrenOfEntityEvent } from '@umbraco-cms/backoffice/entity-action';
import { FormsDataSourceDetailRepository } from '../../../repository/index.js';
import type { FormDataSource } from '../../../../../generated/index.js';
import { FORMS_DATASOURCE_ROOT_ENTITY_TYPE } from '../../../entities.js';
import type { FormsDatasourceDeleteConfirmModalData } from './index.js';

@customElement('forms-datasource-delete-confirm-modal')
export class FormsDatasourceDeleteConfirmModalElement extends UmbModalBaseElement<FormsDatasourceDeleteConfirmModalData> {

	#datasourceToDelete?: FormDataSource | null;

	#datasourceDetailRepository = new FormsDataSourceDetailRepository(this);

	async connectedCallback() {
		super.connectedCallback();

		if (!this.data?.unique) return;

		const datasourceToDeleteResponse = await this.#datasourceDetailRepository.requestByUnique(this.data.unique);
		this.#datasourceToDelete = datasourceToDeleteResponse.data;

		this.requestUpdate();
	}

	async #deleteDatasource(event: PointerEvent) {
		event.stopPropagation();

		if (this.data?.unique) {
			await this.#datasourceDetailRepository.delete(this.data.unique);

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			const eventArgs = {
				entityType: FORMS_DATASOURCE_ROOT_ENTITY_TYPE,
				unique: null,
			};
			const reloadEvent = new UmbRequestReloadChildrenOfEntityEvent(eventArgs);
			eventContext.dispatchEvent(reloadEvent);
		}
		this._submitModal();

		event.stopPropagation();

		if (this.data?.unique) {
			const { data } = await this.#datasourceDetailRepository.requestByUnique(this.data.unique);
			if (!data) throw new Error('Item not found.');

			await this.#datasourceDetailRepository.delete(this.data.unique);

			const eventContext = await this.getContext(UMB_ACTION_EVENT_CONTEXT);
			eventContext.dispatchEvent(event);
		}
		this._submitModal();
	}

	render() {
		return html`
			<umb-body-layout headline=${this.localize.term("formDataSources_deleteDatasource")}>
				<uui-box>
					<p>Are you sure you wish to delete the datasource <b>${this.#datasourceToDelete?.name}</b>?</p>
				</uui-box>
				<uui-button slot="actions" id="cancel" label=${this.localize.term("general_cancel")} @click="${this._rejectModal}">${this.localize.term("general_cancel")}</uui-button>
				<uui-button slot="actions" type="button" label=${this.localize.term("general_delete")} look="primary" color="danger" @click=${this.#deleteDatasource}></uui-button>
			</umb-body-layout>
		`;
	}
}

export default FormsDatasourceDeleteConfirmModalElement;

declare global {
	interface HTMLElementTagNameMap {
		'forms-datasource-delete-confirm-modal': FormsDatasourceDeleteConfirmModalElement;
	}
}
